import{_ as t}from"./chunks/mobile_ai.CbZZkppn.js";import{_ as a,c as e,o as i,a4 as o}from"./chunks/framework.I1cCAST3.js";const l="/assets/mobile_ai_chat.DZ94cIZi.jpg",r="/assets/mobile_ai_term.BPLRKERm.jpg",s="/assets/mobile_ai_history.BCMinB7z.jpg",d="/assets/mobile_ai_chat_approve.CWaFDQKH.jpg",n="/assets/mobile_ai_chat_command_parse.Bv3dX9PR.jpg",c="/assets/mobile_ai_chat_voice.BrqTziRQ.jpg",h="/assets/mobile_ai_chat_voice_correct.C_VLLOQb.jpg",k=JSON.parse('{"title":"AI 会话","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/ai-agent/index.md","filePath":"docs/mobile/ai-agent/index.md"}'),p={name:"docs/mobile/ai-agent/index.md"},g=o('<h1 id="ai-会话" tabindex="-1">AI 会话 <a class="header-anchor" href="#ai-会话" aria-label="Permalink to &quot;AI 会话&quot;">​</a></h1><p>AI 会话是 Chaterm 移动端的核心能力。它让你随时随地用手机处理服务器问题——不只是执行命令，而是真正有 AI 协助你思考、排查和决策。</p><p>无论是在地铁上收到告警、出差时临时排障，还是不确定某条命令该怎么写，你都可以直接在手机上通过自然语言描述问题，让 AI 帮你分析、建议并执行。语音输入则进一步解放了双手，终端与对话的无缝联动让上下文始终连贯。</p><p>移动端主要提供两种模式：<code>对话</code> 和 <code>终端</code>。你可以通过输入框底部的模式选择器在两者之间切换。</p><div class="tip custom-block"><p class="custom-block-title">前提条件</p><p>使用 AI 相关功能（对话模式、语音纠错、命令解释）前，需要先登录账号并在<a href="/docs/mobile/profile/#模型选择">个人中心 &gt; AI 设置 &gt; 模型选择</a>中完成模型配置。</p></div><div style="text-align:center;"><img src="'+t+'" alt="AI chat page" width="320"></div><h2 id="对话模式" tabindex="-1">对话模式 <a class="header-anchor" href="#对话模式" aria-label="Permalink to &quot;对话模式&quot;">​</a></h2><p><code>对话</code> 模式用于与 AI 协作完成分析、解释和命令建议。</p><p>支持文字和语音输入，AI 可解析自然语言生成命令，并根据上下文持续协助排查。</p><p>适合场景：学习 Linux 命令、故障排查、脚本编写、理解配置文件、咨询运维实践。</p><div style="text-align:center;"><img src="'+l+'" alt="Chat mode" width="320"></div><h2 id="终端模式" tabindex="-1">终端模式 <a class="header-anchor" href="#终端模式" aria-label="Permalink to &quot;终端模式&quot;">​</a></h2><p><code>终端</code> 模式直接执行命令，不经过 AI 处理。</p><p>需要先连接服务器，未连接时页面会显示连接入口。支持文字和语音输入，直接返回执行结果。</p><p>适合场景：临时执行命令、快速查看主机状态。</p><div style="text-align:center;"><img src="'+r+'" alt="Terminal mode" width="320"></div><h2 id="上下文联动" tabindex="-1">上下文联动 <a class="header-anchor" href="#上下文联动" aria-label="Permalink to &quot;上下文联动&quot;">​</a></h2><p>手机上做运维排查时，一个典型的困境是：执行了一条命令看到输出，想问 AI 是什么意思，却要手动选中文字、复制、切换输入框、粘贴——手机屏幕小，这个过程非常繁琐。更麻烦的是，如果输出内容很长，手机端根本无法完整选中。</p><p>我们的解法是让两个模式共享同一份会话上下文。在终端模式执行的命令及其输出，切换到对话模式后 AI 可以直接看到，无需复制粘贴。</p><p><strong>典型场景：</strong></p><ol><li>在<strong>终端模式</strong>执行命令，例如 <code>journalctl -n 50</code>，看到一段日志输出</li><li>切换到<strong>对话模式</strong></li><li>直接输入「帮我分析上面的报错」</li><li>AI 基于刚才的命令输出直接给出分析</li></ol><p>这个机制同样适用于其他场景，例如：执行 <code>df -h</code> 后问「哪个分区快满了」，执行自己的脚本 <code>xxx.js</code> 后问「当前任务进度怎样」。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>模式切换不会清空上下文，整个会话期间的终端输出都对 AI 可见。</p></div><h2 id="会话历史" tabindex="-1">会话历史 <a class="header-anchor" href="#会话历史" aria-label="Permalink to &quot;会话历史&quot;">​</a></h2><p>点击页面左上角图标可打开会话历史侧边栏，查看所有历史会话。你可以通过点击或长按对历史会话做更多操作，比如收藏你觉得重要的会话等。</p><h3 id="主要功能" tabindex="-1">主要功能： <a class="header-anchor" href="#主要功能" aria-label="Permalink to &quot;主要功能：&quot;">​</a></h3><ul><li><strong>切换会话</strong>：点击任意历史记录可切换到该会话</li><li><strong>新建会话</strong>：点击侧边栏顶部的新建按钮开始新会话</li><li><strong>编辑标题</strong>：长按会话记录后选择 <code>编辑</code>，可修改会话标题</li><li><strong>收藏会话</strong>：长按会话记录可收藏，收藏项显示在列表顶部</li><li><strong>删除会话</strong>：长按进入多选模式，可批量删除历史记录</li></ul><div style="text-align:center;"><img src="'+s+'" alt="Chat history" width="320"></div><h2 id="命令审批" tabindex="-1">命令审批 <a class="header-anchor" href="#命令审批" aria-label="Permalink to &quot;命令审批&quot;">​</a></h2><p>在 <code>对话</code> 模式下，AI 执行命令前默认会暂停并等待你确认（审批模式）。可在<a href="/docs/mobile/profile/#ai-偏好">个人中心 &gt; AI 偏好</a>中开启<strong>自动执行</strong>，让命令跳过审批直接运行。</p><table tabindex="0"><thead><tr><th>模式</th><th>行为</th></tr></thead><tbody><tr><td><strong>审批模式</strong>（默认）</td><td>每条命令执行前暂停，显示同意 / 拒绝按钮</td></tr><tr><td><strong>自动执行模式</strong></td><td>命令自动执行，无需审批确认</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">危险提示</p><p>自动执行模式下，AI 可能在不逐一确认的情况下连续执行多条命令，建议在熟悉的任务场景或者有把握后再开启。</p></div><div style="text-align:center;"><img src="'+d+'" alt="Chat history" width="320"></div><h2 id="命令解释" tabindex="-1">命令解释 <a class="header-anchor" href="#命令解释" aria-label="Permalink to &quot;命令解释&quot;">​</a></h2><p>在审批模式下，AI 展示待执行命令时，除了同意和拒绝，还可以点击<strong>解读</strong>图标查看命令详情。</p><p><strong>操作按钮说明：</strong></p><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>同意</strong></td><td>确认执行该命令</td></tr><tr><td><strong>拒绝</strong></td><td>取消执行，AI 将停止当前任务</td></tr><tr><td><strong>解读</strong>（文档图标）</td><td>弹出底部面板，由 AI 流式解释该命令的含义和用途</td></tr></tbody></table><p><strong>命令解释面板：</strong></p><p>点击解读图标后，底部弹框会实时显示 AI 对命令的逐步解析，包括：</p><ul><li>命令整体用途与安全性</li><li>各参数的含义</li><li>可能的注意事项或副作用</li></ul><p>命令解释不会触发命令执行，可安全查看后再决定是否同意。</p><div style="text-align:center;"><img src="'+n+'" alt="Chat history" width="320"></div><h2 id="对话语音输入" tabindex="-1">对话语音输入 <a class="header-anchor" href="#对话语音输入" aria-label="Permalink to &quot;对话语音输入&quot;">​</a></h2><p>对话和终端模式均支持语音输入。点击输入框右侧的麦克风图标可切换到语音输入状态。</p><p><strong>使用方式：</strong></p><ol><li>点击麦克风图标，输入框切换为语音输入按钮</li><li><strong>长按</strong>语音按钮开始录音，松手后自动识别</li><li>上滑后松手可取消本次录音</li><li>识别完成后，文字自动发送（对话模式）</li></ol><div style="text-align:center;"><img src="'+c+'" alt="Chat history" width="320"></div><h2 id="语音输入命令" tabindex="-1">语音输入命令 <a class="header-anchor" href="#语音输入命令" aria-label="Permalink to &quot;语音输入命令&quot;">​</a></h2><p>在<strong>终端模式</strong>中，语音识别结果会经过 AI 自动矫正并填入输入框中，通过对语音模型的微调，我们做到了精准识别 SRE 领域命令，解放了手机键盘输入命令的繁琐操作。例如：</p><ul><li>按音调说「kube ctl get po」→ 自动矫正为 <code>kubectl get pods</code></li><li>按音调说「docker 杠a」→ 自动矫正为 <code>docker ps -a</code></li></ul><div style="text-align:center;"><img src="'+h+'" alt="Chat history" width="320"></div><h2 id="典型使用流程" tabindex="-1">典型使用流程 <a class="header-anchor" href="#典型使用流程" aria-label="Permalink to &quot;典型使用流程&quot;">​</a></h2><ol><li>打开 AI 对话页</li><li>连接目标主机</li><li>选择 <code>对话</code> 或 <code>终端</code></li><li>输入问题或命令，或通过语音发起请求</li><li>查看返回结果，按需继续追问</li></ol><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>需要解释、规划和排障时，优先使用 <code>对话</code> 模式</li><li>不熟悉某条命令时，执行前先点击<strong>解读</strong>了解其含义，再决定是否同意</li></ul>',55),m=[g];function _(b,u,x,I,v,A){return i(),e("div",null,m)}const P=a(p,[["render",_]]);export{k as __pageData,P as default};
